    [FormEventHandler(formStr(PurchTable), FormEventType::Initialized)]
    public static void PurchTable_OnInitialized(xFormRun sender, FormEventArgs e)
    {
        DimensionEntryControl dimControlLine    = sender.design().controlName(identifierStr(DimensionEntryControlLine));
        DimensionEntryControl dimControlHeader  = sender.design().controlName(identifierStr(DimensionEntryControlHeader));
        str                   dimAttributeName  = DimensionAttribute::UBSGetTableName(tableStr(VendTable),fieldStr(VendTable,AccountNum));
        str dimAttributeProject = 'Project';

        UBSDefaultDimensionToolKit::disableSeveralDimensionsInForm(dimControlLine, dimAttributeName, dimAttributeProject);
        UBSDefaultDimensionToolKit::disableDimensionInForm(dimControlHeader,dimAttributeName);
    }

    [FormDataFieldEventHandler(formDataFieldStr(PurchTable, PurchTable, OrderAccount), FormDataFieldEventType::Modified)]
    public static void OrderAccount_OnModified(FormDataObject sender, FormDataFieldEventArgs e)
    {
        FormDataSource  formDataSource      = sender.datasource();
        PurchTable      purchTable          = formDataSource.cursor();
        str             dimAttributeName    = DimensionAttribute::UBSGetTableName(tableStr(VendTable),fieldStr(VendTable,AccountNum));

        container conAttribute  = [dimAttributeName];
        container conValue      = [purchTable.OrderAccount];

        DimensionDefault        newDim    = UBSDefaultDimensionToolKit::createDefaultDimension(conAttribute,conValue);
        LedgerDimensionValueSet mergeDim  = UBSDefaultDimensionToolKit::setDimensionValueToDefaultDimension(purchTable.DefaultDimension,newDim,tableStr(VendTable), dimAttributeName);

        purchTable.DefaultDimension = mergeDim;
    }

