    [FormControlEventHandler(formControlStr(PurchTable, PurchTable_UBSProjectDim), FormControlEventType::Lookup)]
    public static void PurchTable_UBSProjectDim_OnLookup(FormControl sender, FormControlEventArgs e)
    {

        UBSProjectDimensionValueLookup::projectDimensionLookup(sender, e);

    }
